export const zkChallenges = [
  // FOUNDATIONS (251-262)
  { id: 251, lang: "ZK", diff: "easy", title: "Modular Arithmetic Basics", concepts: "Modular Arithmetic, Finite Fields, GCD", problem: "Compute 17^13 mod 31 using fast exponentiation. Implement extended Euclidean algorithm to find modular inverse.", why: "All ZK cryptography operates in finite fields — modular arithmetic is the bedrock." },
  { id: 252, lang: "ZK", diff: "easy", title: "Hash Function Properties", concepts: "SHA-256, Collision Resistance, Pre-image", problem: "Hash a string with SHA-256. Then demonstrate: (1) avalanche effect, (2) determinism, (3) why reversing is computationally infeasible.", why: "Hash functions are used in ZK commitments — understanding their properties is mandatory." },
  { id: 253, lang: "ZK", diff: "easy", title: "Commitment Schemes", concepts: "Pedersen Commitment, Hiding, Binding", problem: "Implement a simple Pedersen commitment: C = g^v * h^r mod p. Show it is hiding (r is secret) and binding (can't open to a different value).", why: "Commitments let you prove you know a value without revealing it — foundational ZK primitive." },
  { id: 254, lang: "ZK", diff: "easy", title: "What is a ZK Proof?", concepts: "Completeness, Soundness, Zero-Knowledge", problem: "Implement the classic 3-coloring interactive proof. Prove you can color a graph without revealing the colors in any single round.", why: "3-coloring is the canonical ZK proof example — teaches completeness, soundness, and zero-knowledge." },
  { id: 255, lang: "ZK", diff: "easy", title: "Elliptic Curve Points", concepts: "ECC, Point Addition, secp256k1", problem: "Implement elliptic curve point addition and scalar multiplication on a small curve. Verify the group law (commutativity, associativity).", why: "ZK systems like Groth16 use elliptic curve pairings — EC arithmetic is required knowledge." },
  { id: 256, lang: "ZK", diff: "easy", title: "MiMC Hash Circuit", concepts: "MiMC, Arithmetic Circuits, Field Elements", problem: "Implement the MiMC hash function in Python over a prime field. This is used inside ZK circuits as an efficient hash.", why: "MiMC and Poseidon are ZK-friendly hashes — regular SHA-256 is too expensive to prove in a circuit." },
  { id: 257, lang: "ZK", diff: "easy", title: "Merkle Trees", concepts: "Merkle Tree, Inclusion Proof, Root Hash", problem: "Build a Merkle tree from 8 leaves. Generate an inclusion proof for leaf 3. Verify the proof from root to leaf.", why: "Merkle proofs are everywhere in ZK systems — used to prove set membership without revealing all elements." },
  { id: 258, lang: "ZK", diff: "easy", title: "R1CS: Rank-1 Constraint System", concepts: "R1CS, Constraints, Witness", problem: "Convert the computation x^3 + x + 5 = 35 into an R1CS. Write out all constraints (A, B, C matrices) and compute the witness vector.", why: "R1CS is the universal intermediate representation for zkSNARK circuits — all circuits compile to R1CS." },
  { id: 259, lang: "ZK", diff: "easy", title: "Polynomial Commitments", concepts: "Polynomial, Evaluation, KZG", problem: "Represent the computation f(x) = x^2 + 3x + 5 as a polynomial. Evaluate at x=4. Understand how this enables succinct proofs.", why: "zkSNARKs encode computation as polynomial evaluations — polynomial commitment is the core mechanism." },
  { id: 260, lang: "ZK", diff: "easy", title: "Secret Sharing: Shamir's", concepts: "Shamir Secret Sharing, Threshold, Polynomials", problem: "Implement Shamir's (3,5) secret sharing: split a secret into 5 shares where any 3 reconstruct it using Lagrange interpolation.", why: "Secret sharing underlies threshold cryptography — used in multi-party computation and ZK setups." },
  { id: 261, lang: "ZK", diff: "easy", title: "Fiat-Shamir Heuristic", concepts: "Fiat-Shamir, Non-Interactive, Random Oracle", problem: "Convert an interactive Schnorr identification protocol into a non-interactive proof using Fiat-Shamir (replace verifier's random challenge with a hash).", why: "Fiat-Shamir makes interactive proofs non-interactive — all production SNARKs use this transformation." },
  { id: 262, lang: "ZK", diff: "easy", title: "Nullifiers and Commitments", concepts: "Nullifier, Double-Spend Prevention, Privacy", problem: "Implement a simple private payment scheme: (1) mint = commit(value, secret), (2) spend = reveal nullifier H(secret), (3) verify nullifier wasn't used before.", why: "Nullifiers prevent double-spending in privacy protocols like Zcash and Tornado Cash." },
  // INTERMEDIATE (263-276)
  { id: 263, lang: "ZK", diff: "medium", title: "First Circom Circuit", concepts: "Circom, Constraints, Signals", problem: "Write a Circom circuit that proves you know x such that x^2 = y without revealing x. Compile with circom, generate R1CS, and export verification key.", why: "Circom is the dominant DSL for writing ZK circuits — the first circuit is the gateway to ZK engineering." },
  { id: 264, lang: "ZK", diff: "medium", title: "SnarkJS: Prove and Verify", concepts: "SnarkJS, Groth16, Proof Generation", problem: "Using snarkjs: (1) compile a circuit, (2) run trusted setup (Powers of Tau), (3) generate a witness, (4) create a Groth16 proof, (5) verify the proof.", why: "The full snarkjs workflow is what every ZK developer runs — knowing each step end-to-end is essential." },
  { id: 265, lang: "ZK", diff: "medium", title: "Merkle Proof Circuit", concepts: "Circom, Merkle Tree, Inclusion Proof", problem: "Build a Circom circuit that proves a leaf is in a Merkle tree of depth 10 without revealing which leaf or the other leaves.", why: "Merkle proof circuits are used in every ZK application — airdrop eligibility, private set membership." },
  { id: 266, lang: "ZK", diff: "medium", title: "Range Proof", concepts: "Range Proof, Bit Decomposition, Constraints", problem: "Write a Circom circuit proving a value is in range [0, 2^32) without revealing it. Use bit decomposition and sum constraints.", why: "Range proofs are essential for private finance apps: prove an amount is non-negative without showing it." },
  { id: 267, lang: "ZK", diff: "medium", title: "Poseidon Hash in Circuit", concepts: "Poseidon, ZK-Friendly Hash, Circom", problem: "Use the Poseidon hash function in a Circom circuit to build a commitment scheme. Compare constraint count vs MiMC and SHA-256.", why: "Poseidon is now the dominant ZK-friendly hash — lower constraint count means faster proofs." },
  { id: 268, lang: "ZK", diff: "medium", title: "Groth16 vs PLONK vs STARKs", concepts: "Proof Systems, Tradeoffs, Trusted Setup", problem: "Build the same circuit (quadratic equation proof) using Groth16 (snarkjs) and then PLONK (snarkjs). Compare: proof size, verification time, setup requirements.", why: "Choosing the right proof system is an architectural decision — Groth16 is smallest but requires per-circuit setup." },
  { id: 269, lang: "ZK", diff: "medium", title: "ECDSA Signature Verification in ZK", concepts: "ECDSA, Circuit, Secp256k1", problem: "Prove you know the private key that signed a message (ECDSA signature) without revealing the key. Use circomlib's ECDSA components.", why: "ETH account ownership proofs require ECDSA verification in circuit — foundational for identity systems." },
  { id: 270, lang: "ZK", diff: "medium", title: "Private Token Transfer", concepts: "UTXO, Commitment, Nullifier, Circuit", problem: "Build a UTXO-based private transfer circuit: input nullifiers + new commitments. Prove: (1) you know the input secrets, (2) values balance, (3) nullifiers are valid.", why: "Private transfers are the central use case of Zcash, Tornado Cash, and all private DeFi protocols." },
  { id: 271, lang: "ZK", diff: "medium", title: "ZK Identity: Semaphore", concepts: "Semaphore, Identity, Anonymity, Group", problem: "Run through the Semaphore protocol: (1) generate identity commitment, (2) join a group (Merkle tree), (3) generate anonymous signal proof, (4) verify on-chain.", why: "Semaphore is the reference ZK identity primitive — used by Worldcoin, Unirep, and anonymous voting." },
  { id: 272, lang: "ZK", diff: "medium", title: "ZK-SNARK Trusted Setup", concepts: "Powers of Tau, Ceremony, Toxic Waste", problem: "Run a local Powers of Tau ceremony with snarkjs. Understand what 'toxic waste' is and why multi-party ceremonies exist. Verify transcript integrity.", why: "Trusted setup is critical security knowledge — if done wrong, the entire proof system is broken." },
  { id: 273, lang: "ZK", diff: "medium", title: "Noir: First ZK Program", concepts: "Noir, Aztec, ZK DSL", problem: "Write a Noir program that proves: (1) you know a preimage of a hash, (2) a value is in a private range. Use nargo to compile and prove.", why: "Noir is Aztec's high-level ZK language — more ergonomic than Circom and gaining rapid adoption." },
  { id: 274, lang: "ZK", diff: "medium", title: "Halo2: Without Trusted Setup", concepts: "Halo2, IPA, Recursive Proofs", problem: "Write a simple Halo2 circuit (prove knowledge of Fibonacci sequence). Understand why Halo2 eliminates the trusted setup using IPA commitments.", why: "Halo2 is used by Zcash, Scroll, and Polygon zkEVM — no trusted setup is a significant security property." },
  { id: 275, lang: "ZK", diff: "medium", title: "ZK-Rollup Architecture", concepts: "ZK-Rollup, State Transitions, On-Chain Verification", problem: "Design a minimal ZK-rollup: off-chain state transitions → circuit that proves validity → on-chain verifier contract. Diagram all components.", why: "ZK-rollups (zkSync, Scroll, Polygon zkEVM) are Ethereum's scaling solution — understanding the architecture is required." },
  { id: 276, lang: "ZK", diff: "medium", title: "Recursive SNARKs", concepts: "Recursion, Proof Compression, Nova", problem: "Understand recursive proof composition: use a SNARK to verify another SNARK's proof inside a circuit. Implement a simple chain of 3 recursive proofs.", why: "Recursive proofs enable proof aggregation and compression — used in zkEVMs for batch verification." },
  // ADVANCED (277-280)
  { id: 277, lang: "ZK", diff: "hard", title: "zkEVM: Opcode Constraints", concepts: "zkEVM, EVM Opcodes, Circuit Design", problem: "Constrain a single EVM opcode (e.g., ADD or MSTORE) in a ZK circuit. Understand the state layout (stack, memory, program counter) and how to encode it.", why: "zkEVMs are the hardest engineering problem in crypto — understanding opcode constraints is expert-level." },
  { id: 278, lang: "ZK", diff: "hard", title: "Custom Gate Design in Halo2", concepts: "Halo2, Custom Gates, Lookup Tables", problem: "Implement a custom gate for a range check in Halo2 without bit decomposition. Use a lookup table instead. Measure constraint count reduction.", why: "Custom gates and lookup tables dramatically reduce proof cost — required for production ZK circuit optimization." },
  { id: 279, lang: "ZK", diff: "hard", title: "ZK Proof Aggregation", concepts: "Aggregation, Plonky2, Batch Verification", problem: "Use Plonky2 to aggregate 100 Groth16 proofs into a single proof. Measure: individual vs aggregated verification time and gas cost on-chain.", why: "Proof aggregation is how ZK systems scale to millions of users — Plonky2 is the fastest recursive SNARK." },
  { id: 280, lang: "ZK", diff: "hard", title: "ZK Application: End-to-End", concepts: "Full Stack ZK, On-Chain Verifier, Frontend", problem: "Build a complete ZK app: (1) Circom circuit, (2) Groth16 proof, (3) Solidity verifier contract, (4) React frontend that generates and submits proofs. Deploy to testnet.", why: "Shipping a ZK app end-to-end is the mastery milestone — combines cryptography, smart contracts, and frontend." }
];

export const devopsChallenges = [
  // EASY (281-293)
  { id: 281, lang: "DevOps", diff: "easy", title: "Dockerfile Basics", concepts: "Docker, Dockerfile, Layers", problem: "Write a Dockerfile for a Node.js app: base image, WORKDIR, COPY, RUN npm install, EXPOSE, CMD. Build and run it locally.", why: "Every engineer needs to containerize their own apps — Dockerfile is now a baseline skill." },
  { id: 282, lang: "DevOps", diff: "easy", title: "Docker Compose: Multi-Service", concepts: "Docker Compose, Networks, Volumes", problem: "Write a docker-compose.yml for a web app + PostgreSQL + Redis. Configure a named network, a persistent volume for DB data, and health checks.", why: "Docker Compose is how you run local dev environments — multi-service config is daily work." },
  { id: 283, lang: "DevOps", diff: "easy", title: "Git Workflow: Feature Branch", concepts: "Git, Branching, PR, Rebase", problem: "Implement a feature branch workflow: branch from main, make commits, squash to 1 commit, rebase onto main, open a PR. Document each git command used.", why: "Feature branch + squash + rebase is the dominant engineering workflow at most companies." },
  { id: 284, lang: "DevOps", diff: "easy", title: "CI: First GitHub Actions Pipeline", concepts: "GitHub Actions, YAML, CI", problem: "Write a GitHub Actions workflow that triggers on PR: run lint, run tests, report status. Fail the PR if tests fail.", why: "GitHub Actions is the most widely used CI platform — writing a basic pipeline is baseline knowledge." },
  { id: 285, lang: "DevOps", diff: "easy", title: "Environment Variables & Secrets", concepts: "Secrets, .env, Vault, 12-Factor", problem: "Refactor an app to use environment variables for all config. Add secrets to GitHub Actions. Never commit a secret. Audit for exposed credentials.", why: "Secret management is security-critical — hardcoded secrets are the #1 cause of credential leaks." },
  { id: 286, lang: "DevOps", diff: "easy", title: "Nginx Reverse Proxy", concepts: "Nginx, Proxy, Load Balancing, SSL", problem: "Configure Nginx as a reverse proxy for 3 upstream services. Add path-based routing (/api → service1, / → frontend). Enable SSL with a self-signed cert.", why: "Nginx config is foundational for web infrastructure — path routing and SSL are daily ops tasks." },
  { id: 287, lang: "DevOps", diff: "easy", title: "Log Aggregation Basics", concepts: "Logs, stdout, JSON logging, Loki", problem: "Configure an app to emit structured JSON logs to stdout. Run Loki + Grafana via Docker Compose. Query logs by service name and severity.", why: "Structured logs + centralized aggregation is the baseline for any observable system." },
  { id: 288, lang: "DevOps", diff: "easy", title: "Health Checks & Readiness Probes", concepts: "Health Check, /healthz, Readiness, Liveness", problem: "Add /healthz (liveness) and /readyz (readiness) endpoints to a service. Configure Docker health check. Understand the difference between the two probes.", why: "Health check endpoints are required by every orchestrator — Kubernetes won't route traffic without them." },
  { id: 289, lang: "DevOps", diff: "easy", title: "Bash Scripting for Automation", concepts: "Bash, Shell Scripting, Cron", problem: "Write a bash script that: backs up a directory, timestamps the file, removes backups older than 7 days, and sends an alert if disk > 80%.", why: "Bash scripting is the universal glue in DevOps — every ops engineer writes shell scripts daily." },
  { id: 290, lang: "DevOps", diff: "easy", title: "DNS & Networking Troubleshooting", concepts: "DNS, nslookup, dig, traceroute, curl", problem: "Debug a broken network path: use dig, nslookup, curl -v, traceroute, and netstat to diagnose. Document each tool's output and what it tells you.", why: "Network debugging is an essential on-call skill — knowing each tool's purpose reduces MTTR drastically." },
  { id: 291, lang: "DevOps", diff: "easy", title: "Basic Monitoring: Prometheus + Grafana", concepts: "Prometheus, Metrics, Grafana, Alerts", problem: "Instrument a service with Prometheus metrics (request count, latency histograms). Scrape with Prometheus. Build a Grafana dashboard. Set an alert on high error rate.", why: "Prometheus + Grafana is the standard monitoring stack — instrumenting services is a required skill." },
  { id: 292, lang: "DevOps", diff: "easy", title: "Container Registry: Push and Pull", concepts: "Docker Hub, ECR, GHCR, Image Tags", problem: "Build a Docker image, tag it with semantic versioning, push to GitHub Container Registry. Write a workflow to automate image build + push on every main merge.", why: "Image registry workflows are part of every CI/CD pipeline — artifact management is operational baseline." },
  { id: 293, lang: "DevOps", diff: "easy", title: "SSH & Server Hardening", concepts: "SSH, key auth, UFW, fail2ban", problem: "Secure a Linux server: disable password SSH, enable key-only auth, configure UFW firewall (allow 22/80/443 only), install fail2ban.", why: "Server hardening is minimal viable security — anyone with a cloud server must know these steps." },
  // MEDIUM (294-305)
  { id: 294, lang: "DevOps", diff: "medium", title: "Kubernetes: Deploy a Service", concepts: "Kubernetes, Deployment, Service, kubectl", problem: "Write a Kubernetes Deployment (3 replicas) + Service (ClusterIP) + Ingress for a web app. Deploy to a local cluster (minikube). Perform a rolling update.", why: "Kubernetes is the dominant container orchestrator — writing YAML manifests is required for any backend role." },
  { id: 295, lang: "DevOps", diff: "medium", title: "Helm Chart: Package an App", concepts: "Helm, Charts, Values, Templates", problem: "Create a Helm chart for a 3-tier app (frontend, backend, DB). Use values.yaml for environment config. Deploy across dev and prod namespaces with different values.", why: "Helm is the Kubernetes package manager — charts are how teams manage environment-specific deployments." },
  { id: 296, lang: "DevOps", diff: "medium", title: "Terraform: Provision Infrastructure", concepts: "Terraform, IaC, AWS, State", problem: "Write Terraform to provision: VPC, public subnet, EC2 instance, security group, and S3 bucket for state. Use remote state with locking.", why: "Infrastructure as Code is now required — Terraform is the dominant IaC tool across all clouds." },
  { id: 297, lang: "DevOps", diff: "medium", title: "CI/CD: Full Pipeline", concepts: "CI/CD, Build, Test, Deploy, Rollback", problem: "Build a complete GitHub Actions pipeline: lint → test → build Docker image → push to registry → deploy to Kubernetes → smoke test → rollback on failure.", why: "End-to-end CI/CD pipeline is the gold standard — understanding each stage is required for senior engineers." },
  { id: 298, lang: "DevOps", diff: "medium", title: "GitOps with ArgoCD", concepts: "GitOps, ArgoCD, Sync, Drift Detection", problem: "Set up ArgoCD on a Kubernetes cluster. Sync application state from a Git repo. Simulate drift by manually changing a deployment. Observe auto-correction.", why: "GitOps is the modern deployment paradigm — ArgoCD and Flux are used at every cloud-native company." },
  { id: 299, lang: "DevOps", diff: "medium", title: "Kubernetes: Resource Limits & HPA", concepts: "Resource Limits, HPA, VPA, Autoscaling", problem: "Set CPU/memory requests and limits on a deployment. Configure HPA to scale from 2→10 pods on 50% CPU. Load test with k6 and observe auto-scaling.", why: "Resource management is critical in k8s — without limits, one bad pod can evict the entire node." },
  { id: 300, lang: "DevOps", diff: "medium", title: "Secrets Management: Vault", concepts: "HashiCorp Vault, KV Store, Policies, K8s Auth", problem: "Run Vault in dev mode. Store DB credentials. Configure k8s auth method. Inject secrets into a pod via Vault Agent Injector (annotations).", why: "Vault is the enterprise standard for secrets — k8s + Vault integration is essential for production security." },
  { id: 301, lang: "DevOps", diff: "medium", title: "Distributed Tracing: Jaeger/Tempo", concepts: "OpenTelemetry, Tracing, Spans, Jaeger", problem: "Instrument a 3-service app with OpenTelemetry. Trace a request end-to-end through all services. Visualize in Jaeger. Find the slowest span.", why: "Distributed tracing is mandatory for microservices debugging — without it, cross-service bugs are invisible." },
  { id: 302, lang: "DevOps", diff: "medium", title: "Zero-Downtime Deployment", concepts: "Rolling Update, Blue-Green, Canary, Traffic Splitting", problem: "Implement three deployment strategies for the same app: rolling update, blue-green, and canary (10% traffic). Measure downtime and rollback time for each.", why: "Zero-downtime deployments are a production requirement — knowing all three strategies shows operational maturity." },
  { id: 303, lang: "DevOps", diff: "medium", title: "Service Mesh: Istio Basics", concepts: "Istio, mTLS, Traffic Management, Envoy", problem: "Install Istio on a k8s cluster. Enable mTLS between services. Configure traffic splitting (90/10) between two versions. Visualize traffic in Kiali.", why: "Service mesh is the enterprise approach to service networking — mTLS, observability, and traffic control in one." },
  { id: 304, lang: "DevOps", diff: "medium", title: "Database Migrations in CI/CD", concepts: "Flyway, Liquibase, Schema Migration, Rollback", problem: "Add Flyway database migrations to a CI pipeline. Ensure migrations run before app deployment. Implement a rollback migration. Test the full upgrade+rollback cycle.", why: "Safe schema migrations are one of the hardest problems in production — CI-integrated migrations prevent disasters." },
  { id: 305, lang: "DevOps", diff: "medium", title: "Cost Optimization: FinOps", concepts: "AWS Cost Explorer, Reserved Instances, Spot, Rightsizing", problem: "Analyze a mock AWS bill. Identify top 5 cost drivers. Implement: spot instances for batch workloads, lifecycle policies for S3, rightsizing for underutilized EC2.", why: "FinOps is a growing discipline — cloud costs can exceed engineering salaries if left unmanaged." },
  // HARD (306-310)
  { id: 306, lang: "DevOps", diff: "hard", title: "Multi-Region Active-Active Deployment", concepts: "Multi-Region, DNS Failover, Global LB, replication", problem: "Design and implement an active-active deployment across 2 AWS regions. Use Route53 latency routing, Aurora Global DB, and Redis replication. Test regional failover.", why: "Multi-region is the highest tier of availability engineering — requires deep understanding of data consistency trade-offs." },
  { id: 307, lang: "DevOps", diff: "hard", title: "Chaos Engineering with Chaos Monkey", concepts: "Chaos Engineering, Resilience, Game Days, Fault Injection", problem: "Run chaos experiments on a k8s cluster: kill random pods, inject latency, simulate node failure. Measure MTTR. Document findings and fix weakest points.", why: "Chaos engineering is how Netflix, AWS, and Google find reliability gaps before customers do." },
  { id: 308, lang: "DevOps", diff: "hard", title: "Custom Kubernetes Operator", concepts: "Kubernetes Operator, CRD, controller-runtime, Go", problem: "Build a Kubernetes operator in Go that watches a custom CRD (e.g., DatabaseBackup) and triggers a backup job. Handle reconciliation and error retries.", why: "Operators are how platform teams automate complex operational tasks — writing one shows expert Kubernetes knowledge." },
  { id: 309, lang: "DevOps", diff: "hard", title: "SLO-Based Alerting System", concepts: "SLO, Error Budget, Burn Rate, Alerting", problem: "Define SLOs for a service (99.9% availability, p99 < 200ms). Implement multi-window burn rate alerts in Prometheus. Build an error budget dashboard in Grafana.", why: "SLO-based alerting is how Google SRE manages reliability at scale — it replaces threshold-based alert spam." },
  { id: 310, lang: "DevOps", diff: "hard", title: "Platform Engineering: Internal Developer Platform", concepts: "IDP, Backstage, Self-Service, Golden Paths", problem: "Set up Backstage as an internal developer portal. Add a service catalog, create a software template (golden path) for new services, and integrate with PagerDuty and GitHub.", why: "Platform engineering is the future of DevOps — building an IDP that reduces cognitive load for dev teams is high-leverage work." }
];

export const designChallenges = [
  // EASY (311-323)
  { id: 311, lang: "Design", diff: "easy", title: "Design a URL Shortener", concepts: "Hashing, Redirect, Database, Scale", problem: "Design bit.ly. Requirements: shorten URLs, redirect, analytics. Cover: hash function, collision handling, database schema, redirect flow, and scale to 100M URLs.", why: "URL shortener is the 'Hello World' of system design — every candidate must do this cleanly." },
  { id: 312, lang: "Design", diff: "easy", title: "Design a Rate Limiter", concepts: "Token Bucket, Sliding Window, Redis, API Gateway", problem: "Design a rate limiter for an API (1000 req/min per user). Compare: fixed window, sliding window log, sliding window counter, token bucket. Implement with Redis.", why: "Rate limiting is in every production API — understanding the algorithms and their trade-offs is required." },
  { id: 313, lang: "Design", diff: "easy", title: "Design a Key-Value Store", concepts: "LSM Tree, B-Tree, WAL, Compaction", problem: "Design a distributed KV store like Redis or DynamoDB. Cover: storage engine (LSM vs B-Tree), WAL for durability, replication, and consistent hashing for sharding.", why: "KV store design teaches storage engines, replication, and sharding — foundational distributed systems knowledge." },
  { id: 314, lang: "Design", diff: "easy", title: "Design a Cache System", concepts: "CDN, Cache-Aside, Write-Through, Eviction", problem: "Design a distributed cache. Cover: cache-aside vs write-through vs write-back, eviction policies (LRU/LFU), consistency with source of truth, and cache stampede prevention.", why: "Caching is the most common interview topic — covering all patterns and failure modes is essential." },
  { id: 315, lang: "Design", diff: "easy", title: "Design a Pastebin", concepts: "Object Storage, CDN, TTL, Deduplication", problem: "Design pastebin.com. Cover: blob storage (S3), CDN for read performance, unique ID generation, TTL-based expiry, and deduplication of identical content.", why: "Pastebin has limited scope but covers object storage, CDN, TTL — clean design in 45 minutes." },
  { id: 316, lang: "Design", diff: "easy", title: "Design a Leaderboard", concepts: "Redis Sorted Sets, Real-Time, Ranking, Pagination", problem: "Design a global game leaderboard with real-time rankings for 10M players. Use Redis sorted sets for O(log n) rank queries. Handle pagination and regional leaderboards.", why: "Sorted sets for leaderboards is a classic Redis pattern — tests data structure choice under scale." },
  { id: 317, lang: "Design", diff: "easy", title: "Design a Notification System", concepts: "Push, Email, SMS, Fanout, Queue", problem: "Design a notification system supporting push, email, and SMS. Cover: fanout patterns (push vs pull), priority queues, delivery guarantees, deduplication, and user preferences.", why: "Notification systems appear in every company — covering fanout at scale separates good from great answers." },
  { id: 318, lang: "Design", diff: "easy", title: "Design a Job Queue", concepts: "Message Queue, Worker Pool, Retry, Dead Letter", problem: "Design a distributed job queue (like Sidekiq or Celery). Cover: producer-consumer model, job persistence, at-least-once delivery, retry with backoff, and dead letter queues.", why: "Job queues power every async workflow — covering failure modes and delivery semantics is critical." },
  { id: 319, lang: "Design", diff: "easy", title: "Design an API Gateway", concepts: "API Gateway, Auth, Rate Limiting, Load Balancing", problem: "Design an API gateway (like Kong or AWS API Gateway). Cover: routing, auth (JWT/OAuth), rate limiting, request/response transformation, and circuit breaker.", why: "API gateways are the entry point to every microservices system — every senior engineer must understand them." },
  { id: 320, lang: "Design", diff: "easy", title: "Design a Search Autocomplete", concepts: "Trie, Redis, Typeahead, Rank by Frequency", problem: "Design a search typeahead system (like Google search suggestions). Cover: trie vs Redis sorted sets, prefix indexing, debouncing, and ranking by historical frequency.", why: "Autocomplete is a beloved interview problem — it combines data structures with real-time UX requirements." },
  { id: 321, lang: "Design", diff: "easy", title: "Design a Content Moderation System", concepts: "ML Pipeline, Human Review, Queue, Appeals", problem: "Design a content moderation system for a social platform. Cover: automated ML flagging, confidence thresholds, human review queue, appeals process, and audit trail.", why: "Content moderation is a trust & safety challenge at every social platform — tests policy + systems thinking." },
  { id: 322, lang: "Design", diff: "easy", title: "Design a Metrics Collection System", concepts: "Time Series DB, InfluxDB, Aggregation, Retention", problem: "Design a system to collect metrics from 100K servers (CPU, memory, disk). Cover: agent protocol, time-series DB (InfluxDB/Prometheus), aggregation, downsampling, and alerting.", why: "Metrics infrastructure is foundational for observability — understanding time series DB design is a must." },
  { id: 323, lang: "Design", diff: "easy", title: "Design a File Storage System", concepts: "Object Storage, Chunking, Dedup, S3", problem: "Design Dropbox/Google Drive. Cover: file chunking, deduplication, delta sync, conflict resolution, and object storage (S3). How do you sync across devices efficiently?", why: "File sync design is a common interview problem — delta sync and conflict resolution are the hard parts." },
  // MEDIUM (324-334)
  { id: 324, lang: "Design", diff: "medium", title: "Design Twitter/X Feed", concepts: "Fanout, Timeline, Pull vs Push, Celebrity Problem", problem: "Design Twitter's home timeline. Cover: fanout-on-write vs fanout-on-read, celebrity problem (hybrid approach), cache warming, and real-time delivery via SSE.", why: "Twitter feed design is the most common system design interview question at FAANG — you must know it cold." },
  { id: 325, lang: "Design", diff: "medium", title: "Design a Chat System", concepts: "WebSocket, Message Ordering, Presence, Groups", problem: "Design WhatsApp/Slack. Cover: WebSocket connection management, message ordering (vector clocks), group messaging fanout, presence (online status), and message history.", why: "Chat systems require real-time expertise — WebSockets, presence, ordering, and scale are all testable topics." },
  { id: 326, lang: "Design", diff: "medium", title: "Design Uber/Lyft", concepts: "Geo-Spatial, Matching, ETA, Real-Time Location", problem: "Design a ride-sharing app. Cover: driver location updates (geohashing), rider-driver matching algorithm, surge pricing, ETA computation, and real-time tracking.", why: "Geospatial systems are a unique challenge — geohashing and proximity queries under load are key concepts." },
  { id: 327, lang: "Design", diff: "medium", title: "Design Netflix/YouTube", concepts: "CDN, Video Transcoding, Adaptive Bitrate, Storage", problem: "Design a video streaming platform. Cover: upload pipeline (chunking, transcoding to multiple resolutions), CDN strategy, adaptive bitrate streaming (HLS/DASH), and recommendation.", why: "Video streaming is complex end-to-end — transcoding pipeline + CDN strategy is frequently tested at media companies." },
  { id: 328, lang: "Design", diff: "medium", title: "Design a Distributed Database", concepts: "Sharding, Replication, Consensus, MVCC", problem: "Design a distributed relational DB (like CockroachDB). Cover: horizontal sharding (consistent hashing), multi-leader replication, Raft consensus for HA, and MVCC for transactions.", why: "Distributed DB internals show depth — Raft, MVCC, and sharding together cover the hardest distributed systems concepts." },
  { id: 329, lang: "Design", diff: "medium", title: "Design a Recommendation Engine", concepts: "Collaborative Filtering, Matrix Factorization, Embeddings, Real-Time", problem: "Design a product recommendation system (Amazon). Cover: collaborative filtering, item-based CF, ALS matrix factorization, feature store, real-time vs batch inference.", why: "Recommendation engines drive 35% of Amazon revenue — understanding the full ML + serving pipeline is a strong signal." },
  { id: 330, lang: "Design", diff: "medium", title: "Design Google Maps", concepts: "Graph, Dijkstra, Routing, Geo-Index, ETA", problem: "Design Google Maps. Cover: road network as a graph (trillions of edges), hierarchical routing (A*), real-time traffic updates, ETAs, geospatial indexing, and map tile serving.", why: "Maps is one of the hardest designs — combining graph algorithms, real-time data, and global scale." },
  { id: 331, lang: "Design", diff: "medium", title: "Design an E-Commerce Platform", concepts: "Inventory, Cart, Payment, Order, Idempotency", problem: "Design Amazon's order flow. Cover: inventory management (double-booking prevention), distributed cart, payment processing (idempotency), order saga, and order history.", why: "E-commerce requires transactional correctness under scale — sagas, idempotency, and inventory locking are the hard parts." },
  { id: 332, lang: "Design", diff: "medium", title: "Design a Distributed Lock", concepts: "Redlock, Lease, Fencing Token, ZooKeeper", problem: "Design a distributed lock service. Compare Redlock (Redis) vs ZooKeeper vs etcd. Discuss: split-brain scenarios, lock timeouts, fencing tokens, and lease renewal.", why: "Distributed locks are subtle and frequently broken — understanding the failure modes is an expert-level topic." },
  { id: 333, lang: "Design", diff: "medium", title: "Design a Real-Time Analytics Dashboard", concepts: "Stream Processing, Lambda Architecture, OLAP, Kafka", problem: "Design a real-time analytics pipeline. Cover: Kafka for event ingestion, Flink/Spark Streaming for processing, OLAP store (ClickHouse/Druid) for queries, and dashboard rendering.", why: "Real-time analytics combines streaming + OLAP — understanding the full pipeline is required for data engineering roles." },
  { id: 334, lang: "Design", diff: "medium", title: "Design a Fraud Detection System", concepts: "Real-Time ML, Feature Store, Rules Engine, Kafka", problem: "Design a payment fraud detection system. Cover: real-time feature extraction, rule engine + ML model scoring, feature store for low-latency lookups, and feedback loop for retraining.", why: "Fraud detection combines streaming + ML + low-latency serving — a popular question at fintech companies." },
  // HARD (335-340)
  { id: 335, lang: "Design", diff: "hard", title: "Design a Global CDN", concepts: "CDN, PoPs, Anycast, Cache Invalidation, Edge Computing", problem: "Design a CDN from scratch (like Cloudflare). Cover: PoP placement strategy, anycast routing, cache hierarchy, purge propagation, edge compute, and DDoS mitigation.", why: "CDN design requires deep networking and caching knowledge — anycast and cache invalidation at global scale are expert topics." },
  { id: 336, lang: "Design", diff: "hard", title: "Design a Distributed Tracing System", concepts: "Trace Propagation, Sampling, Span Storage, Jaeger", problem: "Design a distributed tracing system (like Jaeger). Cover: trace context propagation (W3C TraceContext), head-based vs tail-based sampling, span ingestion pipeline, and query engine.", why: "Building observability infrastructure requires understanding sampling theory, ingestion at scale, and query performance." },
  { id: 337, lang: "Design", diff: "hard", title: "Design a Payments System", concepts: "Double-Entry Bookkeeping, Idempotency, Saga, PCI DSS", problem: "Design Stripe. Cover: double-entry ledger, idempotency keys, distributed saga for charge+capture+refund, PCI compliance data isolation, and webhook delivery guarantees.", why: "Payments require the highest correctness bar — double-entry accounting, idempotency, and saga patterns are critical." },
  { id: 338, lang: "Design", diff: "hard", title: "Design a Search Engine", concepts: "Inverted Index, tf-idf, PageRank, Query Parsing, Ranking", problem: "Design a web search engine (like Google at small scale). Cover: web crawling, inverted index, tf-idf ranking, PageRank, query parsing, spell correction, and results caching.", why: "Search engine design tests depth across crawling, indexing, and ranking — each component is independently complex." },
  { id: 339, lang: "Design", diff: "hard", title: "Design a Consensus System", concepts: "Raft, Paxos, Leader Election, Log Replication, etcd", problem: "Design a distributed consensus system like etcd or ZooKeeper. Implement simplified Raft: leader election, log replication, and membership changes. Test partition tolerance.", why: "Consensus algorithms are the bedrock of distributed systems — understanding Raft deeply separates engineers from architects." },
  { id: 340, lang: "Design", diff: "hard", title: "Design an ML Platform", concepts: "Feature Store, Training Pipeline, Model Registry, Serving", problem: "Design an end-to-end ML platform (like Tecton + MLflow + Seldon). Cover: feature store (online + offline), training pipeline, experiment tracking, model registry, A/B serving, and monitoring.", why: "ML platforms are the hardest system design — covering the full lifecycle from feature engineering to production monitoring." }
];

export const tsChallenges = [
  { id: 341, lang: "TS", diff: "easy", title: "Type Annotations Basics", concepts: "Types, Inference, any vs unknown", problem: "Annotate a JS function that takes a user object and returns a greeting. Use strict types. Explain why 'unknown' is safer than 'any'.", why: "TypeScript adoption is near-universal — strict typing basics are table stakes." },
  { id: 342, lang: "TS", diff: "easy", title: "Interfaces vs Types", concepts: "interface, type, extends, intersection", problem: "Define a User with interface and a Product with type. Extend both. Show where they differ: declaration merging (interface) vs union/intersection types.", why: "interface vs type alias is a very common TS interview question — knowing the difference matters." },
  { id: 343, lang: "TS", diff: "easy", title: "Enums and Const Enums", concepts: "enum, const enum, string enum", problem: "Create a string enum for HTTP methods. Use const enum and observe the compiled output. Explain the performance difference.", why: "Enums are used widely in TS projects — const enum is a key optimization worth knowing." },
  { id: 344, lang: "TS", diff: "easy", title: "Generics: Basic Functions", concepts: "Generics, T, constraints", problem: "Write a generic identity function. Then a generic pair<T,U>. Then add a constraint: T extends object. Test with invalid types and observe compile errors.", why: "Generics are the foundation of reusable TS code — writing them is required at senior level." },
  { id: 345, lang: "TS", diff: "easy", title: "Union and Intersection Types", concepts: "Union, Intersection, Discriminated Union", problem: "Model a Result type as Success | Failure. Use a discriminated union with a 'kind' field. Implement a function that handles each case with type narrowing.", why: "Discriminated unions are the TS replacement for inheritance — used extensively in state management." },
  { id: 346, lang: "TS", diff: "easy", title: "Nullability: Strict Checks", concepts: "strictNullChecks, optional chaining, nullish coalescing", problem: "Enable strictNullChecks. Fix all type errors: null checks, optional fields, and optional chaining. Use ?? instead of || for default values.", why: "strictNullChecks eliminates 70% of runtime errors — working with it correctly is essential." },
  { id: 347, lang: "TS", diff: "easy", title: "Type Guards", concepts: "typeof, instanceof, in, narrowing", problem: "Write type guards for: (1) typeof narrowing, (2) instanceof narrowing, (3) a custom 'isUser(obj)' guard function with 'obj is User' return type.", why: "Type guards are how TypeScript narrows union types — used in every production TS codebase." },
  { id: 348, lang: "TS", diff: "medium", title: "Utility Types", concepts: "Partial, Required, Readonly, Pick, Omit, Record", problem: "Use each built-in utility type on a complex User model. Then implement Partial<T> and Pick<T,K> from scratch using mapped types.", why: "Utility types are used in every TS project — implementing them from scratch shows mastery." },
  { id: 349, lang: "TS", diff: "medium", title: "Mapped Types", concepts: "Mapped Types, keyof, in, as", problem: "Create a Nullable<T> mapped type that makes every property T[K] | null. Then create a DeepReadonly<T> that recurses into nested objects.", why: "Mapped types are the most powerful TS feature — deep understanding separates intermediate from expert." },
  { id: 350, lang: "TS", diff: "medium", title: "Template Literal Types", concepts: "Template Literal, infer, conditional types", problem: "Create a type EventName = `on${Capitalize<string>}`. Then create a type that extracts the event name from 'onClick' → 'click'.", why: "Template literal types enable string typing at compile time — used in libraries like Prisma and tRPC." },
  { id: 351, lang: "TS", diff: "medium", title: "Conditional Types", concepts: "Conditional Types, infer, distributive", problem: "Write a NonNullable<T> conditional type. Then write UnwrapPromise<T> that extracts the resolved type from a Promise. Handle nested promises.", why: "Conditional types with infer are how TypeScript standard library is implemented — required for library authors." },
  { id: 352, lang: "TS", diff: "medium", title: "Decorators", concepts: "Class Decorators, Method Decorators, Metadata", problem: "Write a @log decorator that logs method calls with arguments and return values. Write a @validate decorator that validates method inputs against a schema.", why: "Decorators are used in NestJS, TypeORM, Angular — required knowledge for enterprise TS development." },
  { id: 353, lang: "TS", diff: "medium", title: "Declaration Files (.d.ts)", concepts: "Declaration Files, @types, ambient modules", problem: "Write a .d.ts file for an untyped JS library (e.g., a simple math utility). Publish as @types/my-lib. Consume it with full type safety.", why: "Writing declaration files is required when using untyped JS in a TS project — common in real codebases." },
  { id: 354, lang: "TS", diff: "medium", title: "Branded Types", concepts: "Branded Types, nominal typing, type safety", problem: "Create branded types: UserId (brand: 'userId') and OrderId (brand: 'orderId'). Show how they prevent mixing IDs of different entities at compile time.", why: "Branded types implement nominal typing in TS's structural system — prevents entire categories of bugs." },
  { id: 355, lang: "TS", diff: "hard", title: "Type-Safe API Client", concepts: "Generics, Template Literal, Mapped Types, fetch", problem: "Build a type-safe HTTP client where the return type is inferred from the URL path: client.get('/users/:id') returns Promise<User>, client.get('/posts') returns Promise<Post[]>.", why: "Type-safe API clients (like tRPC) eliminate runtime type mismatches — building one shows expert TS." },
  { id: 356, lang: "TS", diff: "hard", title: "Recursive Types", concepts: "Recursive Types, JSON, Deep utility types", problem: "Define a JSON type that recursively accepts string|number|boolean|null|JSON[]|{[k:string]:JSON}. Then write a DeepPartial<T> that works on arbitrarily nested objects.", why: "Recursive types are tricky to get right — they're used in deep utility types and schema validators." },
  { id: 357, lang: "TS", diff: "hard", title: "Variance: Covariance & Contravariance", concepts: "Covariance, Contravariance, in/out, function types", problem: "Explain why (x: Cat) => void is not assignable to (x: Animal) => void. Implement a safe version. Use TS 4.7 variance annotations (in/out).", why: "Variance is the hardest type theory concept in TS — understanding it prevents subtle type safety bugs." },
  { id: 358, lang: "TS", diff: "hard", title: "Builder Pattern with TypeScript", concepts: "Builder, Fluent API, Generic Accumulator", problem: "Build a type-safe query builder where chaining .where() adds to the type and .build() returns a typed result reflecting all chained calls.", why: "Type-safe builders use advanced generics — Prisma and Drizzle are built this way." },
  { id: 359, lang: "TS", diff: "hard", title: "Strict Config: tsconfig Best Practices", concepts: "tsconfig, strict, paths, project refs", problem: "Configure a monorepo tsconfig: strict mode, path aliases, project references, composite mode. Measure type-checking performance before and after optimization.", why: "tsconfig mastery is required for large projects — proper configuration prevents false positives and slow builds." },
  { id: 360, lang: "TS", diff: "hard", title: "Plugin Architecture with TS", concepts: "Plugin System, Declaration Merging, Module Augmentation", problem: "Use module augmentation to allow plugins to add new fields to a core interface without modifying it. Demonstrate with a logger plugin that extends Express Request.", why: "Module augmentation is how frameworks like Express and NextAuth extend base types — essential for library design." }
];

export const securityChallenges = [
  { id: 361, lang: "Security", diff: "easy", title: "OWASP Top 10 Overview", concepts: "OWASP, Injection, XSS, CSRF, Broken Auth", problem: "For each of the OWASP Top 10, describe: (1) what it is, (2) a real-world example, (3) how to prevent it. Focus on the top 3: Injection, Broken Auth, XSS.", why: "OWASP Top 10 is the baseline security knowledge for every engineer — asked in most security reviews." },
  { id: 362, lang: "Security", diff: "easy", title: "SQL Injection: Find and Fix", concepts: "SQL Injection, Parameterized Queries, ORM", problem: "Find the SQL injection vulnerability in: `query = 'SELECT * FROM users WHERE id = ' + userId`. Exploit it. Fix with parameterized queries. Test with SQLMap.", why: "SQL injection is still the #1 web vulnerability — finding and fixing it is a baseline skill." },
  { id: 363, lang: "Security", diff: "easy", title: "XSS: Stored and Reflected", concepts: "XSS, CSP, Sanitization, DOMPurify", problem: "Demonstrate stored XSS: inject <script>alert(1)</script> into a comment field. Then fix: (1) output encoding, (2) CSP headers, (3) DOMPurify sanitization.", why: "XSS has been in OWASP Top 10 for 20 years — every front-end engineer must understand and prevent it." },
  { id: 364, lang: "Security", diff: "easy", title: "Authentication: JWT vs Session", concepts: "JWT, Session, Cookie, HttpOnly, Secure", problem: "Implement both JWT and session-based auth. Compare: storage (localStorage vs HttpOnly cookie), revocation, scaling. Identify which is safer and why.", why: "JWT vs session auth is one of the most common security debate topics in engineering interviews." },
  { id: 365, lang: "Security", diff: "easy", title: "Password Hashing: bcrypt", concepts: "bcrypt, salt, rainbow tables, Argon2", problem: "Hash passwords with bcrypt (cost factor 12). Show why MD5/SHA1 are wrong for passwords. Demo rainbow table attack. Compare bcrypt vs Argon2id.", why: "Correct password hashing is non-negotiable — every auth system must do this right." },
  { id: 366, lang: "Security", diff: "easy", title: "HTTPS and TLS Deep Dive", concepts: "TLS, Certificate, HSTS, mTLS, ALPN", problem: "Explain TLS 1.3 handshake step by step. Configure HSTS with preloading. Set up mTLS between two services. Check cert expiry automation.", why: "Understanding TLS is required for any engineer handling user data — HSTS and cert rotation are ops basics." },
  { id: 367, lang: "Security", diff: "easy", title: "CORS: Configuration and Attacks", concepts: "CORS, Origin, Preflight, Access-Control headers", problem: "Set up a CORS misconfiguration (allow all origins). Exploit it with a crafted request. Fix: whitelist specific origins + validate. Test preflight handling.", why: "CORS misconfigurations are a very common finding in security audits — understanding the full flow is required." },
  { id: 368, lang: "Security", diff: "medium", title: "OAuth 2.0 and PKCE", concepts: "OAuth 2.0, PKCE, Authorization Code Flow, Token", problem: "Implement OAuth 2.0 authorization code flow with PKCE. Handle: code verifier, code challenge, token exchange, refresh tokens, token storage securely.", why: "OAuth 2.0 with PKCE is now the standard for secure auth flows — every company uses it." },
  { id: 369, lang: "Security", diff: "medium", title: "SSRF: Server-Side Request Forgery", concepts: "SSRF, Metadata API, DNS Rebinding, Allowlist", problem: "Exploit an SSRF vulnerability to read AWS EC2 metadata endpoint. Bypass filter that blocks 169.254.0.0/16 using DNS rebinding. Fix with strict allowlist.", why: "SSRF is in OWASP Top 10 2021 — particularly dangerous in cloud environments with metadata APIs." },
  { id: 370, lang: "Security", diff: "medium", title: "Secrets Scanning and Rotation", concepts: "Secret Scanning, GitGuardian, Rotation, Vault", problem: "Audit a GitHub repo for leaked secrets (API keys, passwords). Set up GitGuardian. Rotate the leaked credentials. Add pre-commit hooks to prevent future leaks.", why: "Secret leaks are the #1 source of cloud breaches — proactive scanning and rotation is required practice." },
  { id: 371, lang: "Security", diff: "medium", title: "Security Headers", concepts: "CSP, HSTS, X-Frame-Options, Referrer-Policy", problem: "Audit a web app's security headers with securityheaders.com. Add: CSP with nonce, HSTS, X-Frame-Options, Referrer-Policy. Verify with OWASP ZAP.", why: "Security headers are a quick win — misconfigured headers are cited in almost every web security audit." },
  { id: 372, lang: "Security", diff: "medium", title: "Encryption at Rest and in Transit", concepts: "AES-256, Envelope Encryption, KMS, Field Encryption", problem: "Implement field-level encryption for PII (SSN, credit card) using AES-256-GCM + KMS key wrapping. Verify ciphertext is stored, plaintext never logged.", why: "PII encryption is a regulatory requirement (GDPR, PCI DSS) — understanding envelope encryption is essential." },
  { id: 373, lang: "Security", diff: "medium", title: "Rate Limiting and Brute Force Prevention", concepts: "Rate Limiting, Account Lockout, CAPTCHA, Device Fingerprint", problem: "Implement login rate limiting: 5 attempts → 15min lockout. Add CAPTCHA after 3 failures. Add device fingerprinting. Defend against distributed brute force.", why: "Credential stuffing attacks are automated — without rate limiting, any auth endpoint is a target." },
  { id: 374, lang: "Security", diff: "medium", title: "Dependency Vulnerability Scanning", concepts: "npm audit, Snyk, CVE, Supply Chain", problem: "Run npm audit on a real project. Use Snyk to scan. Identify CVEs, their CVSS scores, and fix them. Add automated scanning to CI. Block PRs with critical vulns.", why: "Supply chain attacks (Log4Shell, XZ Utils) made dep scanning a required practice, not optional." },
  { id: 375, lang: "Security", diff: "hard", title: "Threat Modeling: STRIDE", concepts: "STRIDE, Attack Surface, Mitigations, Data Flow Diagram", problem: "Take a simple web app. Draw a data flow diagram. Apply STRIDE to each component: identify Spoofing, Tampering, Repudiation, Info Disclosure, DoS, Elevation threats.", why: "Threat modeling is how security engineers think proactively — STRIDE is the standard framework at Microsoft, Google." },
  { id: 376, lang: "Security", diff: "hard", title: "JWT Attacks: Algorithm Confusion", concepts: "JWT, alg:none, RS256→HS256, Key Confusion", problem: "Exploit the JWT 'alg:none' vulnerability and the RS256→HS256 confusion attack. Fix: pin algorithm in validation, use asymmetric keys correctly.", why: "JWT attacks are common CTF and bug bounty findings — understanding them prevents auth bypass." },
  { id: 377, lang: "Security", diff: "hard", title: "Penetration Testing Basics", concepts: "Pen Test, Burp Suite, OWASP ZAP, Recon", problem: "Run a basic penetration test on a deliberately vulnerable app (DVWA or Juice Shop): recon → scanning → exploitation → reporting. Use Burp Suite as a proxy.", why: "Understanding how attackers think is the most effective way to build secure systems." },
  { id: 378, lang: "Security", diff: "hard", title: "Zero-Trust Architecture", concepts: "Zero Trust, BeyondCorp, mTLS, Policy Engine, Service Identity", problem: "Design a zero-trust network: no implicit trust based on IP/network. Every service must authenticate (mTLS). Use OPA for policy enforcement. Diagram trust flows.", why: "Zero-trust is now the enterprise security model — Google, Microsoft, and AWS all mandate it internally." },
  { id: 379, lang: "Security", diff: "hard", title: "Secure SDLC", concepts: "SAST, DAST, Code Review, Security Gates", problem: "Build a Secure SDLC pipeline: SAST (CodeQL) + SCA (Snyk) + secret scanning in CI, DAST (ZAP) in staging, required security review for auth/crypto changes.", why: "Shifting security left into the development process reduces the cost of bugs by 100x — required knowledge for tech leads." },
  { id: 380, lang: "Security", diff: "hard", title: "Incident Response Playbook", concepts: "IR, DFIR, Chain of Custody, Containment, Post-Mortem", problem: "Simulate a credential leak incident: detection → triage → containment (rotate keys) → eradication → recovery → post-mortem. Write a 5-page IR report.", why: "Incident response is what separates reactive from proactive security culture — every eng leader must know the process." }
];

export const sqlChallenges = [
  { id: 381, lang: "SQL", diff: "easy", title: "SELECT Fundamentals", concepts: "SELECT, WHERE, ORDER BY, LIMIT", problem: "Query a sales table: (1) all orders > $100, (2) top 10 by amount, (3) orders between two dates. Use aliases, BETWEEN, and IN.", why: "Basic SELECT proficiency is required for any backend role — clean query writing is tablestakes." },
  { id: 382, lang: "SQL", diff: "easy", title: "JOINs: All Types", concepts: "INNER, LEFT, RIGHT, FULL OUTER, CROSS JOIN", problem: "Given users and orders tables, write queries for: (1) all users with their orders (LEFT JOIN), (2) only matched rows (INNER), (3) all combinations (CROSS JOIN). Explain the difference.", why: "JOIN types are the most tested SQL topic — explaining the difference clearly is required." },
  { id: 383, lang: "SQL", diff: "easy", title: "Aggregations and GROUP BY", concepts: "COUNT, SUM, AVG, GROUP BY, HAVING", problem: "Find total revenue per product category. Filter categories with > 1000 orders. Order by revenue descending. Use GROUP BY, HAVING, and aggregate functions.", why: "GROUP BY + HAVING is the core of analytical SQL — used in every BI and reporting query." },
  { id: 384, lang: "SQL", diff: "easy", title: "Subqueries and EXISTS", concepts: "Subquery, EXISTS, IN, correlated subquery", problem: "Find all customers who placed an order in the last 30 days using: (1) subquery with IN, (2) correlated subquery with EXISTS. Compare their execution plans.", why: "Correlated subqueries vs EXISTS is a common SQL optimization topic in interviews." },
  { id: 385, lang: "SQL", diff: "easy", title: "Window Functions", concepts: "ROW_NUMBER, RANK, LAG, LEAD, PARTITION BY", problem: "Rank salespeople by revenue within each region (PARTITION BY region). Find each user's previous order amount (LAG). Identify top 3 products per category.", why: "Window functions are the most powerful SQL feature for analytics — ROW_NUMBER, LAG, LEAD, RANK are daily tools." },
  { id: 386, lang: "SQL", diff: "easy", title: "CTEs: Common Table Expressions", concepts: "WITH, CTE, Recursive CTE", problem: "Rewrite a complex nested subquery as a CTE. Then write a recursive CTE to traverse a hierarchical employee table (manager → subordinates).", why: "CTEs transform unreadable nested queries into clean, maintainable SQL — recursive CTEs handle trees." },
  { id: 387, lang: "SQL", diff: "medium", title: "Indexing Strategy", concepts: "B-Tree, Composite Index, Covering Index, Index Scan vs Seq Scan", problem: "Add an index to speed up: (1) single-column lookup, (2) multi-column range query, (3) a query that can use a covering index. Use EXPLAIN ANALYZE to compare.", why: "Choosing the right index is the most impactful database optimization skill — wrong indexes slow things down." },
  { id: 388, lang: "SQL", diff: "medium", title: "Query Optimization: EXPLAIN", concepts: "EXPLAIN ANALYZE, Sequential Scan, Nested Loop, Hash Join", problem: "Take a slow query (5+ second runtime). Use EXPLAIN ANALYZE to find the bottleneck. Add appropriate index. Rewrite the query to avoid a full table scan.", why: "Reading EXPLAIN output is how database engineers diagnose performance issues — a required skill." },
  { id: 389, lang: "SQL", diff: "medium", title: "Transaction Isolation Levels", concepts: "READ UNCOMMITTED, READ COMMITTED, REPEATABLE READ, SERIALIZABLE", problem: "Demonstrate each isolation level with a concurrent transaction scenario: dirty read, non-repeatable read, phantom read. Show which level prevents each anomaly.", why: "Isolation levels are tested in senior interviews — understanding dirty reads vs phantom reads is required." },
  { id: 390, lang: "SQL", diff: "medium", title: "Database Normalization", concepts: "1NF, 2NF, 3NF, BCNF, Denormalization", problem: "Take an unnormalized orders table. Normalize to 3NF step by step. Then consciously denormalize for read performance — document the tradoff.", why: "Normalization vs denormalization is a key design decision — knowing when to break the rules is the real skill." },
  { id: 391, lang: "SQL", diff: "medium", title: "Partitioning: Range and Hash", concepts: "Table Partitioning, Range, Hash, List, Partition Pruning", problem: "Partition an orders table by: (1) date range (monthly), (2) customer_id hash (8 buckets). Verify partition pruning with EXPLAIN. Query a single partition.", why: "Table partitioning is how you scale tables to billions of rows — partition pruning is the key performance benefit." },
  { id: 392, lang: "SQL", diff: "medium", title: "Locking and Deadlocks", concepts: "Row Locks, Table Locks, Deadlock, NOWAIT, FOR UPDATE", problem: "Reproduce a deadlock between two transactions. Detect it with pg_locks. Fix by enforcing consistent lock ordering. Use SELECT FOR UPDATE NOWAIT.", why: "Deadlocks cause production outages — every backend engineer must know how to detect and prevent them." },
  { id: 393, lang: "SQL", diff: "medium", title: "Full-Text Search in PostgreSQL", concepts: "tsvector, tsquery, GIN Index, Ranking", problem: "Add full-text search to a products table using tsvector + GIN index. Rank results by relevance (ts_rank). Compare performance vs LIKE '%term%'.", why: "PostgreSQL full-text search eliminates Elasticsearch for many use cases — it's powerful and often overlooked." },
  { id: 394, lang: "SQL", diff: "medium", title: "JSONB: PostgreSQL JSON Queries", concepts: "JSONB, GIN Index, JSON operators, partial index", problem: "Store user preferences as JSONB. Query nested fields with ->> and @>. Add a GIN index. Create a partial index only on records with a specific JSON key.", why: "JSONB makes PostgreSQL a document store — knowing JSON operators and indexing is required for modern apps." },
  { id: 395, lang: "SQL", diff: "hard", title: "Replication: Primary-Replica Setup", concepts: "WAL, Streaming Replication, Lag, Read Replicas", problem: "Set up PostgreSQL streaming replication. Monitor replication lag. Route read queries to replicas. Handle failover when primary goes down. Promote replica to primary.", why: "Replication is how you scale PostgreSQL reads and achieve HA — every production DB setup uses it." },
  { id: 396, lang: "SQL", diff: "hard", title: "Sharding Patterns", concepts: "Horizontal Sharding, Shard Key, Cross-Shard Queries, Resharding", problem: "Shard a users table across 4 PostgreSQL instances by user_id % 4. Handle: (1) cross-shard JOINs, (2) global secondary indexes, (3) resharding when adding a 5th shard.", why: "Sharding is the only path past vertical scaling limits — resharding without downtime is the hardest part." },
  { id: 397, lang: "SQL", diff: "hard", title: "Optimistic vs Pessimistic Locking", concepts: "Optimistic Lock, Pessimistic Lock, version column, CAS", problem: "Implement optimistic locking with a version column (reject updates if version changed). Compare with SELECT FOR UPDATE (pessimistic). Benchmark under high concurrency.", why: "Choosing the right locking strategy for concurrent updates is a core architecture decision." },
  { id: 398, lang: "SQL", diff: "hard", title: "MVCC: Multi-Version Concurrency Control", concepts: "MVCC, Visibility Rules, VACUUM, Bloat", problem: "Observe MVCC in PostgreSQL: see dead tuples with pg_stat_user_tables. Run VACUUM ANALYZE. Implement autovacuum tuning for a high-write table.", why: "MVCC is how PostgreSQL achieves concurrent reads without locks — understanding bloat and VACUUM is ops-critical." },
  { id: 399, lang: "SQL", diff: "hard", title: "Connection Pooling: PgBouncer", concepts: "PgBouncer, Pool Modes, Max Connections, Prepared Statements", problem: "Add PgBouncer between app and PostgreSQL. Configure transaction pooling. Measure connection overhead with and without pooling. Handle prepared statement limitations.", why: "PgBouncer is mandatory at scale — PostgreSQL's process-per-connection model doesn't scale to thousands of clients." },
  { id: 400, lang: "SQL", diff: "hard", title: "Time-Series with TimescaleDB", concepts: "TimescaleDB, Hypertables, Continuous Aggregates, Compression", problem: "Create a TimescaleDB hypertable for sensor data. Set retention policy (delete after 90 days). Build a continuous aggregate for hourly averages. Enable compression.", why: "TimescaleDB extends PostgreSQL for time-series at scale — the #1 alternative to InfluxDB." }
];

export const archChallenges = [
  { id: 401, lang: "Arch", diff: "easy", title: "Domain-Driven Design: Bounded Contexts", concepts: "DDD, Bounded Context, Ubiquitous Language, Context Map", problem: "Model an e-commerce domain: identify bounded contexts (Orders, Inventory, Payments, Shipping). Define context boundaries, anti-corruption layers, and shared kernel.", why: "DDD is the dominant approach for complex domain modeling — bounded contexts prevent the 'big ball of mud'." },
  { id: 402, lang: "Arch", diff: "easy", title: "Hexagonal Architecture", concepts: "Ports and Adapters, Domain, Application, Infrastructure", problem: "Refactor a monolithic service into hexagonal architecture: domain core (no dependencies), ports (interfaces), and adapters (DB, HTTP, Kafka). Draw the dependency diagram.", why: "Hexagonal architecture makes code testable and replaceable — it's the standard for clean service design." },
  { id: 403, lang: "Arch", diff: "easy", title: "CQRS: Command Query Separation", concepts: "CQRS, Command, Query, Read Model, Write Model", problem: "Implement CQRS for a blog: write side (commands: CreatePost, PublishPost) updates the DB; read side queries a denormalized read model optimized for listing.", why: "CQRS enables independent scaling of reads and writes — used wherever read/write performance requirements differ." },
  { id: 404, lang: "Arch", diff: "easy", title: "Event Sourcing", concepts: "Event Store, Event Replay, Snapshots, Projections", problem: "Implement an account balance system using event sourcing: store Deposited/Withdrawn events, rebuild balance by replaying. Add snapshots every 100 events.", why: "Event sourcing provides a complete audit trail and time-travel debugging — used in fintech and healthcare." },
  { id: 405, lang: "Arch", diff: "easy", title: "Saga Pattern", concepts: "Saga, Choreography, Orchestration, Compensating Transactions", problem: "Implement an order saga with compensating transactions: (1) reserve inventory → (2) charge payment → (3) ship. On payment failure, release inventory automatically.", why: "Sagas solve distributed transactions without 2PC — the standard pattern for multi-service workflows." },
  { id: 406, lang: "Arch", diff: "easy", title: "Strangler Fig Pattern", concepts: "Strangler Fig, Migration, Routing, Proxy", problem: "Incrementally migrate a monolith to microservices using Strangler Fig: route /users/* to new service, /orders/* still to monolith. Document the migration phases.", why: "Strangler Fig is how you safely migrate legacy systems — the alternative (big bang rewrite) is how projects fail." },
  { id: 407, lang: "Arch", diff: "easy", title: "Outbox Pattern", concepts: "Transactional Outbox, At-Least-Once, CDC, Debezium", problem: "Implement the outbox pattern: write DB record + outbox entry in one transaction. Use Debezium (CDC) to publish outbox events to Kafka. Handle duplicates idempotently.", why: "The outbox pattern guarantees at-least-once event delivery without dual-write problems — production-critical." },
  { id: 408, lang: "Arch", diff: "medium", title: "Event-Driven Architecture", concepts: "Event-Driven, Kafka, Choreography, Loose Coupling", problem: "Redesign a synchronous order processing system as event-driven: OrderPlaced → InventoryService, PaymentService, NotificationService react via Kafka topics.", why: "Event-driven architecture is how you decouple microservices — understanding choreography vs orchestration is required." },
  { id: 409, lang: "Arch", diff: "medium", title: "Circuit Breaker Pattern", concepts: "Circuit Breaker, Hystrix, Resilience4j, Half-Open State", problem: "Implement a circuit breaker with three states: Closed, Open, Half-Open. Configure thresholds. Test failure detection and recovery. Compare with retry + timeout.", why: "Circuit breakers prevent cascade failures — they're the standard resiliency pattern for service dependencies." },
  { id: 410, lang: "Arch", diff: "medium", title: "Anti-Corruption Layer", concepts: "ACL, Translation, Facade, Legacy Integration", problem: "Integrate with a legacy system's verbose XML API. Build an ACL that translates it into clean domain objects. Ensure the legacy model never leaks into your domain.", why: "ACLs protect your domain from external model pollution — critical when integrating legacy systems." },
  { id: 411, lang: "Arch", diff: "medium", title: "API Versioning Strategies", concepts: "URI versioning, Header versioning, Semantic Versioning, Deprecation", problem: "Implement three API versioning strategies: URL (/v1/users), Accept header, and query param. Implement a deprecation policy with sunset headers. Handle breaking changes.", why: "API versioning is a public commitment — doing it wrong breaks clients and destroys developer trust." },
  { id: 412, lang: "Arch", diff: "medium", title: "Backend for Frontend (BFF)", concepts: "BFF, API Aggregation, Client-Specific API", problem: "Design a BFF layer for a mobile app and a web app that both consume the same microservices. The BFF aggregates and transforms responses for each client's specific needs.", why: "BFF is the standard for optimizing API responses per client — used by Netflix, SoundCloud, and every large mobile app." },
  { id: 413, lang: "Arch", diff: "medium", title: "Bulkhead Pattern", concepts: "Bulkhead, Thread Pool Isolation, Resource Partitioning", problem: "Implement bulkhead isolation: separate thread pools for critical vs non-critical operations. Simulate a slow non-critical call. Verify it doesn't exhaust resources for critical ones.", why: "Bulkheads prevent one failing component from sinking the whole ship — foundational for resilient systems." },
  { id: 414, lang: "Arch", diff: "medium", title: "SOLID in Practice", concepts: "SOLID, SRP, OCP, LSP, ISP, DIP", problem: "Refactor a God class that handles user auth, emails, and billing. Apply SRP (split), OCP (extend without modifying), ISP (smaller interfaces), DIP (inject dependencies).", why: "SOLID principles are the foundation of maintainable OOP design — every engineering interview asks about them." },
  { id: 415, lang: "Arch", diff: "hard", title: "Microservices: Data Ownership", concepts: "Data Ownership, No Shared DB, Private Tables, Sidecar", problem: "Enforce the 'one DB per service' rule. Move shared tables to their owning service. Implement API calls and async events to replace direct DB joins across service boundaries.", why: "Data ownership is the hardest microservices discipline — violating it creates the distributed monolith anti-pattern." },
  { id: 416, lang: "Arch", diff: "hard", title: "Idempotency at Scale", concepts: "Idempotency Key, Exactly-Once, Deduplication, Conditional Updates", problem: "Make a payment processing endpoint fully idempotent: (1) client sends idempotency key, (2) server deduplicates, (3) returns same result for replays, (4) handles concurrent duplicates.", why: "Idempotency is required for safe retries — every payment, order, and state-mutating API must be idempotent." },
  { id: 417, lang: "Arch", diff: "hard", title: "Eventual Consistency Patterns", concepts: "Eventual Consistency, Reconciliation, Read-Your-Writes, Causal Consistency", problem: "Design a system that is eventually consistent: show how to handle read after write (user creates post, immediately reads — post missing), and reconcile conflicts.", why: "Eventual consistency trade-offs are core to distributed systems design — every architect must reason about them." },
  { id: 418, lang: "Arch", diff: "hard", title: "Service Decomposition: Mono to Micro", concepts: "Decomposition, Domain Boundaries, Anti-Patterns, Migration", problem: "Take a monolith and decompose it: identify domain boundaries using dependency analysis, extract the least-coupled module first, validate with fitness functions.", why: "Monolith-to-microservices migrations fail more often than they succeed — safe strategies are a senior leadership skill." },
  { id: 419, lang: "Arch", diff: "hard", title: "Fitness Functions for Architecture", concepts: "Fitness Functions, Architectural Tests, ArchUnit, Automated Governance", problem: "Use ArchUnit to enforce architectural rules as tests: no direct DB access from controllers, no circular dependencies, services can't import from other service internals.", why: "Fitness functions prevent architecture erosion over time — they automate what code reviews miss." },
  { id: 420, lang: "Arch", diff: "hard", title: "Architecture Decision Records", concepts: "ADR, Trade-offs, Context, Consequences, Governance", problem: "Write 3 ADRs: (1) choosing PostgreSQL over MongoDB, (2) adopting CQRS for the order service, (3) deprecating REST in favor of gRPC for internal services.", why: "ADRs are how mature engineering orgs capture architectural decisions — writing them is a leadership signal." }
];

